int sumArray(vector<int> &numbers, int index)
{
    if (index == numbers.size()) // BASE CASE — nothing left to add
    {
        return 0;
    }
    return numbers[index] + sumArray(numbers, index + 1); // RECURSIVE CASE
}

#include <iostream>

using namespace std;

int fibonacci(int n)
{
    if (n <= 1) // BASE CASE
    {
        return n;
    }
    return fibonacci(n - 1) + fibonacci(n - 2); // RECURSIVE CASE — calls itself TWICE
}

