    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* mergeTwoLists(ListNode* list1, ListNode* list2)
{
    vector<int> values;
    for (ListNode* n = list1; n; n = n->next) values.push_back(n->val);
    for (ListNode* n = list2; n; n = n->next) values.push_back(n->val);

    sort(values.begin(), values.end());

    ListNode dummy(0);
    ListNode* tail = &dummy;
    for (int v : values)
    {
        tail->next = new ListNode(v);
        tail = tail->next;
    }

    return dummy.next;
}

