#include <iostream>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* mergeTwoLists(ListNode* list1, ListNode* list2)
{
    if (list1 == nullptr) return list2;
    if (list2 == nullptr) return list1;

    if (list1->val <= list2->val)
    {
        list1->next = mergeTwoLists(list1->next, list2);
        return list1;
    }
    else
    {
        list2->next = mergeTwoLists(list1, list2->next);
        return list2;
    }
}

int main()
{
    ListNode* list1 = new ListNode(1);
    list1->next = new ListNode(2);
    list1->next->next = new ListNode(4);

    ListNode* list2 = new ListNode(1);
    list2->next = new ListNode(3);
    list2->next->next = new ListNode(4);

    ListNode* merged = mergeTwoLists(list1, list2);
    for (ListNode* n = merged; n; n = n->next) cout << n->val << " ";

    return 0;
}

#include <iostream>
#include <string>

using namespace std;

int kthGrammar(int n, int k)
{
    string row = "0";

    for (int i = 2; i <= n; i++)
    {
        string next = "";
        for (char c : row)
        {
            next += (c == '0') ? "01" : "10";
        }
        row = next;
    }

    return row[k - 1] - '0';
}

int main()
{
    cout << kthGrammar(4, 5) << endl;

    return 0;
}

#include <iostream>

using namespace std;

int kthGrammar(int n, int k)
{
    if (n == 1) return 0; // base case: row 1 is always "0"

    int parent = kthGrammar(n - 1, (k + 1) / 2);

    if (k % 2 == 1) return parent;      // first half of the pair — same as parent
    return 1 - parent;                  // second half of the pair — flipped
}

int main()
{
    cout << kthGrammar(4, 5) << endl;

    return 0;
}

